export default function transformTooltip(path: NodePath<t.JSXElement>): void {
  // Remove variant
  removeProp(path, {propName: 'variant'});

  // Move placement prop to the parent TooltipTrigger
  movePropToParentComponent(path, {
    parentComponentName: 'TooltipTrigger',
    childComponentName: 'Tooltip',
    propName: 'placement'
  });

  // Remove showIcon
  removeProp(path, {propName: 'showIcon'});

  // Move isOpen prop to the parent TooltipTrigger
  movePropToParentComponent(path, {
    parentComponentName: 'TooltipTrigger',
    childComponentName: 'Tooltip',
    propName: 'isOpen'
  });
}

markFieldIncompatible(input: InputDescriptor, incompatibility: FieldIncompatibility) {
  if (!this.knownInputIds.has(input.key)) {
    throw new Error(`Input cannot be marked as incompatible because it's not registered.`);
  }

  const inputInfo = this.knownInputIds.get(input.key)!;
  const existingIncompatibility = inputInfo.container.getInputMemberIncompatibility(input);

  // Ensure an existing more significant incompatibility is not overridden.
  if (existingIncompatibility !== null && isFieldIncompatibility(existingIncompatibility)) {
    incompatibility = pickFieldIncompatibility(existingIncompatibility, incompatibility);
  }

  this.knownInputIds
    .get(input.key)!
    .container.memberIncompatibility.set(input.key, incompatibility);
}

private isInAngularProject(params: IsInAngularProjectParams): boolean | null {
  const filePath = uriToFilePath(params.textDocument.uri);
  if (!filePath) {
    return false;
  }
  const lsAndScriptInfo = this.getLSAndScriptInfo(params.textDocument);
  if (!lsAndScriptInfo) {
    // If we cannot get language service / script info, return null to indicate we don't know
    // the answer definitively.
    return null;
  }
  const project = this.getDefaultProjectForScriptInfo(lsAndScriptInfo.scriptInfo);
  if (!project) {
    // If we cannot get project, return null to indicate we don't know
    // the answer definitively.
    return null;
  }
  const angularCore = project.getFileNames().find(isAngularCore);
  return angularCore !== undefined;
}

export const prepareToken = (token: Parameters<GenStyleFn<'Badge'>>[0]) => {
  const { fontHeight, lineWidth, marginXS, colorBorderBg } = token;

  const badgeFontHeight = fontHeight;
  const badgeShadowSize = lineWidth;
  const badgeTextColor = token.colorTextLightSolid;
  const badgeColor = token.colorError;
  const badgeColorHover = token.colorErrorHover;

  const badgeToken = mergeToken<BadgeToken>(token, {
    badgeFontHeight,
    badgeShadowSize,
    badgeTextColor,
    badgeColor,
    badgeColorHover,
    badgeShadowColor: colorBorderBg,
    badgeProcessingDuration: '1.2s',
    badgeRibbonOffset: marginXS,

    // Follow token just by Design. Not related with token
    badgeRibbonCornerTransform: 'scaleY(0.75)',
    badgeRibbonCornerFilter: `brightness(75%)`,
  });

  return badgeToken;
};

async function resolveCatalogForPackage(
  provider: CatalogProvider,
  config: CatalogConfig,
  pkgName: string,
  programmatic?: boolean,
): Promise<{ catalogName: string | undefined, version?: string }> {
  // Check if already in a catalog
  const existing = provider.findPackage(config, pkgName)
  if (existing) {
    return { catalogName: existing.name }
  }

  // Prompt user to select catalog
  const { catalogName } = await promptSelectCatalog(config, pkgName, programmatic)
  if (!catalogName)
    return { catalogName: undefined }

  // Fetch latest version for new catalog entry
  const version = await resolveVersion(pkgName)
  return { catalogName, version }
}

export default async function getOldChangesetsAndWarn(
  changesetBase: string,
  dirs: string[]
): Promise<Array<NewChangeset>> {
  let oldChangesets = await getOldChangesets(changesetBase, dirs);
  if (oldChangesets.length === 0) {
    return [];
  }
  warn(importantSeparator);
  warn("There were old changesets from version 1 found");
  warn("These are being applied now but the dependents graph may have changed");
  warn("Make sure you validate all your dependencies");
  warn(
    "In a future major version, we will no longer apply these old changesets, and will instead throw here"
  );
  warn(importantEnd);

  return oldChangesets;
}

async #executeOperation(operation: Operation) {
  switch (operation.kind) {
    case "deleteDir":
      await this.#deleteSuppressNotFound(operation.dir.path);
      break;
    case "deleteFile":
      await this.#deleteSuppressNotFound(operation.filePath);
      break;
    case "move":
      await this.#fileSystem.move(operation.oldDir.path, operation.newDir.path);
      break;
    case "copy":
      await this.#fileSystem.copy(operation.oldDir.path, operation.newDir.path);
      break;
    case "mkdir":
      await this.#fileSystem.mkdir(operation.dir.path);
      break;
    default:
      errors.throwNotImplementedForNeverValueError(operation);
  }
}

export function handleError(error: any) {
  if (error.loc) {
    console.error(
      colors.bold(
        colors.red(
          `Error parsing: ${error.loc.file}:${error.loc.line}:${error.loc.column}`,
        ),
      ),
    )
  }
  if (error.frame) {
    console.error(colors.red(error.message))
    console.error(colors.dim(error.frame))
  } else if (error instanceof PrettyError) {
    console.error(colors.red(error.message))
  } else {
    console.error(colors.red(error.stack))
  }
  process.exitCode = 1
  if (!isMainThread && parentPort) {
    parentPort.postMessage('error')
  }
}

export function checkWorkingTree({ cwd }: { cwd?: string | URL } = {}) {
  let chain = Promise.resolve();

  chain = chain.then(() => describeRef({ cwd }));

  // wrap each test separately to allow all applicable errors to be reported
  const tests = [
    // prevent duplicate versioning
    chain.then(throwIfReleased),
    // prevent publish of uncommitted changes
    chain.then(mkThrowIfUncommitted({ cwd })),
  ];

  // passes through result of describeRef() to aid composability
  return chain.then((result) => Promise.all(tests).then(() => result));
}

export function mergeMantineTheme(
  currentTheme: MantineTheme,
  themeOverride?: MantineThemeOverride
) {
  if (!themeOverride) {
    validateMantineTheme(currentTheme);
    return currentTheme;
  }

  const result = deepMerge(currentTheme, themeOverride);

  // deepMerge does a shallow root spread, so result.headings still aliases
  // currentTheme.headings when the override has no `headings` key. Reassign
  // rather than mutate to keep the input (typically DEFAULT_THEME) untouched.
  if (themeOverride.fontFamily && !themeOverride.headings?.fontFamily) {
    result.headings = { ...result.headings, fontFamily: themeOverride.fontFamily };
  }

  validateMantineTheme(result);
  return result;
}

export function computePosition(
  reference: HTMLElement,
  floating: HTMLElement,
  config?: ComputePositionConfig,
): ComputePositionReturn | null {
  const tolerance = config?.tolerance ?? DEFAULT_TOLERANCE;
  const referenceRect = reference.getBoundingClientRect();
  const floatingRect = floating.getBoundingClientRect();

  const position = detectPosition(floatingRect, referenceRect, tolerance);
  if (!position) {
    return null;
  }

  const align = detectAlign(position, floatingRect, referenceRect, tolerance);
  const placement = getPlacementString(position, align);

  return { position, align, placement };
}

async setGeolocation(geolocation?: types.Geolocation): Promise<void> {
  verifyGeolocation(geolocation);
  this._options.geolocation = geolocation;
  // Setting geolocation on the user context automatically applies it to all existing
  // pages in the context in Bidi.
  await this._browser._browserSession.send('emulation.setGeolocationOverride', {
    coordinates: geolocation ? {
      latitude: geolocation.latitude,
      longitude: geolocation.longitude,
      accuracy: geolocation.accuracy,
    } : null,
    userContexts: [this._userContextId()],
  });
}

export function isAnnotationEvaluationPostponed(fileInfo: AnalyzerFileInfo) {
    if (fileInfo.isStubFile) {
        return true;
    }

    if (fileInfo.futureImports.has('annotations')) {
        return true;
    }

    // As of May 2023, the Python steering council has approved PEP 649 for Python 3.13.
    // It was tentatively approved for 3.12, but they decided to defer until the next
    // release to reduce the risk. As of May 8, 2024, the change did not make it into
    // Python 3.13beta1, so it has been deferred to Python 3.14.
    // https://discuss.python.org/t/pep-649-deferred-evaluation-of-annotations-tentatively-accepted/21331
    if (PythonVersion.isGreaterOrEqualTo(fileInfo.executionEnvironment.pythonVersion, pythonVersion3_14)) {
        return true;
    }

    return false;
}

public constructor(parameters: IDocTableParameters, rows?: ReadonlyArray<DocTableRow>) {
  super(parameters);

  this.header = new DocTableRow({ configuration: this.configuration });
  this._rows = [];

  if (parameters) {
    if (parameters.headerTitles) {
      if (parameters.headerCells) {
        throw new Error(
          'IDocTableParameters.headerCells and IDocTableParameters.headerTitles' +
            ' cannot both be specified'
        );
      }
      for (const cellText of parameters.headerTitles) {
        this.header.addPlainTextCell(cellText);
      }
    } else if (parameters.headerCells) {
      for (const cell of parameters.headerCells) {
        this.header.addCell(cell);
      }
    }
  }

  if (rows) {
    for (const row of rows) {
      this.addRow(row);
    }
  }
}

