public getCompletionsForExpression(expression: nodes.Expression, result: CompletionList): CompletionList {
	const parent = expression.getParent();
	if (parent instanceof nodes.FunctionArgument) {
		this.getCompletionsForFunctionArgument(parent, <nodes.Function>parent.getParent(), result);
		return result;
	}

	const declaration = <nodes.Declaration>expression.findParent(nodes.NodeType.Declaration);
	if (!declaration) {
		this.getTermProposals(undefined, null, result);
		return result;
	}

	const node = expression.findChildAtOffset(this.offset, true);
	if (!node) {
		return this.getCompletionsForDeclarationValue(declaration, result);
	}
	if (node instanceof nodes.NumericValue || node instanceof nodes.Identifier) {
		return this.getCompletionsForDeclarationValue(declaration, result);
	}
	return result;
}

private _ComputeDiff(originalStart: number, originalEnd: number, modifiedStart: number, modifiedEnd: number, pretty: boolean): IDiffResult {
	const quitEarlyArr = [false];
	let changes = this.ComputeDiffRecursive(originalStart, originalEnd, modifiedStart, modifiedEnd, quitEarlyArr);

	if (pretty) {
		// We have to clean up the computed diff to be more intuitive
		// but it turns out this cannot be done correctly until the entire set
		// of diffs have been computed
		changes = this.PrettifyChanges(changes);
	}

	return {
		quitEarly: quitEarlyArr[0],
		changes: changes
	};
}

public setSchemaContributions(schemaContributions: ISchemaContributions): void {
	if (schemaContributions.schemas) {
		const schemas = schemaContributions.schemas;
		for (const id in schemas) {
			const normalizedId = normalizeId(id);
			this.contributionSchemas[normalizedId] = this.addSchemaHandle(normalizedId, schemas[id]);
		}
	}
	if (Array.isArray(schemaContributions.schemaAssociations)) {
		const schemaAssociations = schemaContributions.schemaAssociations;
		for (let schemaAssociation of schemaAssociations) {
			const uris = schemaAssociation.uris.map(normalizeId);
			const association = this.addFilePatternAssociation(schemaAssociation.pattern, schemaAssociation.folderUri, uris);
			this.contributionAssociations.push(association);
		}
	}
}

private async sendPendingFullTextDocumentChanges(connection: Connection): Promise<void> {
	return this._pendingChangeSemaphore.lock(async () => {
		try {
			const changes = this._didChangeTextDocumentFeature!.getPendingDocumentChanges(this._inFlightOpenNotifications);
			if (changes.length === 0) {
				return;
			}
			for (const document of changes) {
				const params = this.code2ProtocolConverter.asChangeTextDocumentParams(document);
				// We await the send and not the delivery since it is more or less the same for
				// notifications.
				await connection.sendNotification(DidChangeTextDocumentNotification.type, params);
				this._didChangeTextDocumentFeature!.notificationSent(document, DidChangeTextDocumentNotification.type, params);
			}
		} catch (error) {
			this.error(`Sending pending changes failed`, error, false);
			throw error;
		}
	});
}

export async function reportSolutions(
	nextSolutionPromise: Promise<SolutionsStream>,
	solutionHandler: ISolutionHandler
): Promise<void> {
	const nextSolution = await nextSolutionPromise;
	switch (nextSolution.status) {
		case 'Solution':
			await solutionHandler.onSolution(nextSolution.solution);
			await reportSolutions(nextSolution.next, solutionHandler);
			break;
		case 'FinishedNormally':
			await solutionHandler.onFinishedNormally();
			break;
		case 'FinishedWithError':
			await solutionHandler.onFinishedWithError(nextSolution.error);
			break;
	}
}

function addStoreForFeatureImport(
  tree: Tree,
  isParentStandalone,
  route: string,
  sourceFile: SourceFile,
  parentPath: string,
  provideStoreForFeature: string,
  storeForFeature: string
) {
  if (isParentStandalone) {
    const parentContents = tree.read(parentPath, 'utf-8');
    if (parentContents.includes('ApplicationConfig')) {
      addProviderToAppConfig(tree, parentPath, provideStoreForFeature);
    } else if (parentContents.includes('bootstrapApplication')) {
      addProviderToBootstrapApplication(
        tree,
        parentPath,
        provideStoreForFeature
      );
    } else {
      addProviderToRoute(tree, parentPath, route, provideStoreForFeature);
    }
  } else {
    sourceFile = addImportToModule(
      tree,
      sourceFile,
      parentPath,
      storeForFeature
    );
  }
  return sourceFile;
}

async function cacheArgs(
  cmdArgs: ArgInput<any>,
  respectNoCacheDefault: boolean,
): Promise<Record<string, Command.Arg.Cached>> {
  const promises = Object.entries(cmdArgs).map(async ([name, arg]) => [
    name,
    {
      default: await cacheDefaultValue(arg, respectNoCacheDefault),
      description: arg.description,
      hidden: arg.hidden,
      multiple: arg.multiple,
      name,
      noCacheDefault: arg.noCacheDefault,
      options: arg.options,
      required: arg.required,
    },
  ])
  return Object.fromEntries(await Promise.all(promises))
}

export function getPatchInfo (
  patchFileGroups: PatchGroupRecord | undefined,
  pkgName: string,
  pkgVersion: string
): ExtendedPatchInfo | undefined {
  if (!patchFileGroups?.[pkgName]) return undefined

  const exactVersion = patchFileGroups[pkgName].exact[pkgVersion]
  if (exactVersion) return exactVersion

  const satisfied = patchFileGroups[pkgName].range.filter(item => satisfies(pkgVersion, item.version))
  if (satisfied.length > 1) {
    throw new PatchKeyConflictError(pkgName, pkgVersion, satisfied)
  }
  if (satisfied.length === 1) {
    return satisfied[0].patch
  }

  return patchFileGroups[pkgName].all
}

#convertIsolationLevel(clientIsolationLevel: Tx.IsolationLevel | undefined): SqlIsolationLevel | undefined {
  switch (clientIsolationLevel) {
    case undefined:
      return undefined
    case 'ReadUncommitted':
      return 'READ UNCOMMITTED'
    case 'ReadCommitted':
      return 'READ COMMITTED'
    case 'RepeatableRead':
      return 'REPEATABLE READ'
    case 'Serializable':
      return 'SERIALIZABLE'
    case 'Snapshot':
      return 'SNAPSHOT'
    default:
      throw new PrismaClientKnownRequestError(
        `Inconsistent column data: Conversion failed: Invalid isolation level \`${
          clientIsolationLevel satisfies never
        }\``,
        {
          code: 'P2023',
          clientVersion: this.config.clientVersion,
          meta: {
            providedIsolationLevel: clientIsolationLevel,
          },
        },
      )
  }
}

documentSymbolHandler(documentSymbolParams: DocumentSymbolParams): DocumentSymbol[] | SymbolInformation[] {
  const document = this.yamlSettings.documents.get(documentSymbolParams.textDocument.uri);

  if (!document) {
    return;
  }

  const onResultLimitExceeded = this.onResultLimitExceeded(
    document.uri,
    this.yamlSettings.maxItemsComputed,
    'document symbols'
  );

  const context = { resultLimit: this.yamlSettings.maxItemsComputed, onResultLimitExceeded };

  if (this.yamlSettings.hierarchicalDocumentSymbolSupport) {
    return this.languageService.findDocumentSymbols2(document, context);
  } else {
    return this.languageService.findDocumentSymbols(document, context);
  }
}

