function supportRanges() {
  // Fix breaking configuration for `jsdom < 16`
  if (window.Range) {
    window.Range.prototype.getClientRects = Element.prototype.getClientRects;
    window.Range.prototype.getBoundingClientRect = Element.prototype.getBoundingClientRect;
  }

  function fakeCreateRange() {
    return {
      setStart: noop,
      setEnd: noop,
      commonAncestorContainer: {
        nodeName: 'BODY',
        ownerDocument: document,
      } as Node,
      getClientRects: Element.prototype.getClientRects,
      getBoundingClientRect: Element.prototype.getBoundingClientRect,
    } as any;
  }

  // Create a fake range for selections.
  document.createRange = document.createRange ?? fakeCreateRange;
}

function relativeImportSource(from: string, to: string) {
  let path = Path.relative(Path.dirname(from), to);

  let extension = Path.extname(path);

  // no extension
  path = Path.join(Path.dirname(path), Pathe.filename(path));
  if (!path.startsWith("../")) path = "./" + path;

  // In typescript, we want to support "moduleResolution": "nodenext" as well as not having "allowImportingTsExtensions": true,
  // so we normalize all JS like files to `.js`, but allow other extensions such as `.mdx` and others that might be used as routes.
  if (!extension || /\.(js|ts)x?$/.test(extension)) {
    extension = ".js";
  }

  return path + extension;
}

applyDeoptimizations() {
	this.deoptimized = true;
	if (this.variable instanceof LocalVariable) {
		// When accessing a variable from a module without side effects, this
		// means we use an export of that module and therefore need to potentially
		// include it in the bundle.
		if (!this.variable.module.isExecuted) {
			markModuleAndImpureDependenciesAsExecuted(this.variable.module);
		}
		this.variable.consolidateInitializers();
		this.scope.context.requestTreeshakingPass();
	}
	if (this.isVariableReference) {
		this.variable!.addUsedPlace(this);
		this.scope.context.requestTreeshakingPass();
	}
}

export function deserializeError(serialized: SerializedError): Error {
  // A generic Error is intentional: this reconstructs an arbitrary error thrown in another runtime
  // (its original class cannot cross the realm boundary). Storybook-specific fields like `code` and
  // `fromStorybook` are restored from `properties`, so callers can still branch on them.
  // eslint-disable-next-line local-rules/no-uncategorized-errors
  const error = new Error(serialized.message);
  error.name = serialized.name;

  if (serialized.stack !== undefined) {
    error.stack = serialized.stack;
  }
  if ('cause' in serialized) {
    error.cause = fromTransportSafe(serialized.cause);
  }
  if (serialized.properties) {
    for (const [key, value] of Object.entries(serialized.properties)) {
      (error as unknown as Record<string, unknown>)[key] = fromTransportSafe(value);
    }
  }

  return error;
}
